package gigachat

// Промпты для AI-сервисов. План §17.2.
//
// Все промпты требуют STRICT-JSON ответа, чтобы парсить без эвристик.
// Пользовательский ввод подставляется только в user-сообщение (не в system),
// чтобы избежать prompt injection (план §17.4 / §19.6).

const (
	// SystemRecommender — подбор мероприятия по интересу.
	SystemRecommender = `Ты помощник приёмной комиссии университета.
Твоя задача — подобрать абитуриенту наиболее подходящие мероприятия из заданного списка.

Правила:
- НЕ выдумывай мероприятий. Используй только список ниже.
- Если ничего не подходит — верни пустой массив recommendations.
- Возвращай ТОЛЬКО валидный JSON по схеме, без пояснений и без markdown.

Схема ответа:
{
  "recommendations": [
    { "event_id": 0, "title": "string", "reason": "string (1-2 предложения, до 200 символов)" }
  ]
}`

	// UserRecommenderTemplate — шаблон user-сообщения для подбора.
	// %s = interest, %s = JSON-список событий.
	UserRecommenderTemplate = `Интерес пользователя: %s

Доступные мероприятия (JSON):
%s

Верни 1-2 наиболее подходящих.`

	// SystemRewriter — улучшение текста рассылки.
	SystemRewriter = `Ты помогаешь организатору университетского мероприятия написать понятное уведомление.

Правила:
- Сохрани смысл исходного текста.
- Сделай текст официальным, коротким (до 600 символов), дружелюбным.
- Обязательно укажи дату, время и место, если они есть в контексте.
- НЕ добавляй фактов, которых нет в исходном тексте или контексте.
- Возвращай ТОЛЬКО валидный JSON без пояснений и без markdown.

Схема ответа:
{ "text": "string" }`

	// UserRewriterTemplate — шаблон user-сообщения для rewrite.
	// %s = исходный текст, %s = название, %s = дата/время, %s = место.
	UserRewriterTemplate = `Исходный текст:
%s

Контекст мероприятия:
Название: %s
Дата и время: %s
Место: %s`

	// SystemSummary — управленческая сводка по событию.
	SystemSummary = `Ты формируешь короткую управленческую сводку по мероприятию для организатора.

Правила:
- 3-5 коротких предложений.
- Назови ключевые числа.
- В конце — одна практическая рекомендация.
- Возвращай ТОЛЬКО валидный JSON без пояснений и без markdown.

Схема ответа:
{ "summary": "string" }`

	// UserSummaryTemplate — шаблон user-сообщения для сводки.
	// %s = title, %d = capacity/registered/free/waitlist/cancelled, %s = top interests.
	UserSummaryTemplate = `Данные по мероприятию:
Название: %s
Всего мест: %d
Записано: %d
Свободно: %d
В листе ожидания: %d
Отменили: %d
Топ интересов: %s`
)
